   reverse(sorted_nums.begin(),sorted_nums.end());

   const size_t sz{nums.size()};

   long max_product{-INF}; 

   /* Iterate over pairs from largest element downwards till sqrt(size). This reduces iterations significantly compared to nested loops.*/

